// The educational medication-descriptions dataset, loaded onto the curated-dataset
// framework (issue #860 Track B, wave 2). Copies the mets.ts / icd10-common.ts shape:
// import the envelope JSON (generated by scripts/gen-medication-descriptions.ts),
// validate it once with loadDataset(), and build a MULTI-VALUE matcher so one entry
// resolves under any of its names (generic + brand names + alternate spellings). The
// registry lists this dataset for the linter; lib/medication-info.ts is the DOMAIN
// accessor that consumes it. Pure — no DB, no network.
//
// Identity is the per-entry `match_keys` union, folded by normalizeMedName (the SAME
// strip-strength/form + lowercase the stored med names are grouped by), so a stored
// "Ibuprofen 200 mg" query lands on the "Ibuprofen" entry. The refusal gate holds: a
// name no entry carries resolves to null, never a nearest-guess.

import rawMeds from "./data/medication-descriptions.json";
import { loadDataset } from "./loader";
import { createMatcher, multiValueStrategy } from "./matcher";
import { cleanMedicationName } from "@/lib/prescription-parse";
import type { MedDescriptionEntry } from "@/scripts/gen-medication-descriptions";

export type {
  MedDescriptionEntry,
  MedicationTypical,
} from "@/scripts/gen-medication-descriptions";

// The validated dataset (envelope + guarantees). Throws at module load if the committed
// JSON ever violates the contract — a loud, early failure.
export const medicationDescriptionsDataset =
  loadDataset<MedDescriptionEntry>(rawMeds);

// Normalize a raw medication name to the lookup key form: strip a trailing
// strength/form via cleanMedicationName (the same grouping used for stored meds), then
// lowercase and collapse whitespace. The single normalization both the stored match
// keys and an incoming query fold through. (Lives here — the framework layer — so the
// matcher strategy and lib/medication-info.ts share ONE definition; medication-info
// re-exports it for its consumers.)
export function normalizeMedName(raw: unknown): string {
  if (typeof raw !== "string" || raw === "") return "";
  return cleanMedicationName(raw).toLowerCase().replace(/\s+/g, " ").trim();
}

// Identity strategy: the multi-value `match_keys` field, each key folded by
// normalizeMedName. One entry indexes under its generic + brands + synonyms; an unknown
// name refuses (null).
export const medDescriptionsStrategy = multiValueStrategy(
  "match_keys",
  normalizeMedName
);

// The multi-value matcher (the framework refusal gate).
const matcher = createMatcher(
  medicationDescriptionsDataset,
  medDescriptionsStrategy
);

// Every medication entry in curated (source) order.
export const MED_DESCRIPTION_ENTRIES: MedDescriptionEntry[] =
  medicationDescriptionsDataset.entries;

// The medication entry a name resolves to (by generic / brand / synonym), or null when
// the drug is not in the curated set. Case-insensitive; strength/form stripped.
export function medEntryForName(
  name: string | null | undefined
): MedDescriptionEntry | null {
  return matcher.match(name);
}
